mapper.update:
/* 회의 상태/종료일시 수정 ai.meeting.updateMeetingStatus */
UPDATE TB_MEETING SET
    STATUS      = #{status}
    , END_DT    = NOW()
    , MODIFY_DT = NOW()
WHERE MEETING_ID = #{meetingId}

/* 회의 제목 수정 (AI 자동 생성 반영) ai.meeting.updateMeetingTitle */
UPDATE TB_MEETING SET
    MEETING_TITLE = #{meetingTitle}
    , MODIFY_DT = NOW()
WHERE MEETING_ID = #{meetingId}

mapper.select:
/* 회의 참석자 조회 ai.meeting.selectMeetingAttendees */
SELECT
    JSON_ARRAYAGG(
        JSON_OBJECT('userId', JT.user_id, 'userNm', JT.user_nm)
    ) AS INTEGRATED_ATTENDEES
FROM (
    SELECT DISTINCT sub.user_id, sub.user_nm
    FROM TB_MEETING M,
    JSON_TABLE(
        M.ATTENDEES,
        '$[*]' COLUMNS (
            user_id VARCHAR(100) PATH '$.userId',
            user_nm VARCHAR(100) PATH '$.userNm'
        )
    ) AS sub
    WHERE M.MEETING_ID IN

            #{id}

) JT

mapper.update:
/* 회의록 수정 ai.meeting.updateMeetingMinutes */ UPDATE TB_MEETING_MINUTES
FULL_TEXT = #{fullText}, FLAT_DATA = #{flatData}, GENERATED_CONTENT = #{generatedContent}, EDITED_CONTENT = #{editedContent}, MODIFY_DT = NOW()
WHERE MINUTES_ID = #{minutesId}

/* 인포그래픽 이미지/상태 수정 ai.meeting.updateMeetingInfographic */
UPDATE TB_MEETING_INFOGRAPHIC SET
    INFOGRAPHIC_IMG = #{infographicImg}
    , STATUS        = #{infographicStatus}
    , MODIFY_DT     = NOW()
WHERE INFOGRAPHIC_ID = #{infographicId}

/* 화자 매핑 (실명/사용자ID) 수정 ai.meeting.updateSpeakerMapping */
UPDATE TB_MEETING_SPEAKER SET
    SPEAKER_NM  = #{speakerNm}
    , USER_ID   = #{speakerUserId}
    , MODIFY_DT = NOW()
WHERE SPEAKER_ID = #{speakerId}

/* 화자 utterances + 이름 수정 (머지 결과 저장) ai.meeting.updateSpeakerUtterances */
UPDATE TB_MEETING_SPEAKER SET
    SPEAKER_NM  = #{speakerNm}
    , USER_ID   = #{speakerUserId}
    , UTTERANCES = #{utterances}
    , MODIFY_DT = NOW()
WHERE SPEAKER_ID = #{speakerId}

mapper.delete:
/* 화자 행 삭제 (머지 후 중복 제거) ai.meeting.deleteSpeaker */
DELETE FROM TB_MEETING_SPEAKER
WHERE SPEAKER_ID = #{speakerId}

/* 회의 화자 전체 삭제 ai.meeting.deleteSpeakersByMeetingId */
DELETE FROM TB_MEETING_SPEAKER
WHERE MEETING_ID = #{meetingId}

mapper.update:
/* 오디오 처리 상태 수정 ai.meeting.updateMeetingAudioStatus */
UPDATE TB_MEETING_AUDIO SET
    STATUS      = #{audioStatus}
    , DURATION_SEC = #{durationSec}
    ,    ERROR_MSG    = #{errorMsg}
    , MODIFY_DT = NOW()
WHERE MEETING_ID = #{meetingId}

/* Heartbeat 수신 시 최종 일시 갱신 ai.meeting.updateMeetingHeartbeat */
UPDATE TB_MEETING SET
    LAST_HEARTBEAT_DT = NOW()
    , MODIFY_DT = NOW()
WHERE MEETING_ID = #{meetingId}

mapper.delete:
/* 회의 오디오 레코드 전체 삭제 (복구 전 정리) ai.meeting.deleteAudioByMeetingId */
DELETE FROM TB_MEETING_AUDIO
WHERE MEETING_ID = #{meetingId}
